#include <bits/stdc++.h>
using namespace std;
const int N=2e5+5;
int n,y[N],c[N],l[N],r[N];
int lowbit(int x){
    return x&(-x);
}
int Sum(int x){
    if(x==0)
        return 0;
    return c[x]+Sum(x-lowbit(x));
}
void Plus(int x){
    if(x>n)
        return;
    c[x]++;
    Plus(x+lowbit(x));
}
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d",&y[i]);
    for(int i=1;i<=n;i++){
        l[i]=Sum(y[i]-1);
        Plus(y[i]);
    }
    memset(c,0,sizeof(c));
    for(int i=n;i;i--){
        r[i]=Sum(y[i]-1);
        Plus(y[i]);
    }
    long long ans1=0,ans2=0;
    for(int i=2;i<n;i++)
        ans2+=1LL*l[i]*r[i],ans1+=1LL*(i-l[i]-1)*(n-i-r[i]);
    printf("%lld %lld",ans1,ans2);
    return 0;
}
